import{_ as o,o as e,c as s,R as c}from"./chunks/framework.byfcZK4E.js";const h=JSON.parse('{"title":"1.VsCode 配置JS代码保存自动格式化","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq/2-vscode.md","filePath":"guide/faq/2-vscode.md","lastUpdated":1702006628000}'),t={name:"guide/faq/2-vscode.md"},a=c('<h1 id="_1-vscode-配置js代码保存自动格式化" tabindex="-1">1.VsCode 配置JS代码保存自动格式化 <a class="header-anchor" href="#_1-vscode-配置js代码保存自动格式化" aria-label="Permalink to &quot;1.VsCode 配置JS代码保存自动格式化&quot;">​</a></h1><p><code>Prettier</code> 是一个很有特色的代码格式化工具，它可以使整个代码库的格式化过程自动化。因此在设置好 <code>Prettier</code> 之后，你不再需要与同事讨论代码格式化规则、分号、换行符等问题了。它会导入你所有代码，删除所有格式，并根据其样式规则重新格式化代码</p><ol><li>在扩展工具中安装<code>Prettier</code></li></ol><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202312080936514.png" alt="image-20231208093605422"></p><ol><li>设置自动保存文件 打开设置，搜索框搜索<code>files.autoSave</code> 我们把设置项属性选择为<code>onFocuschange</code></li></ol><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202312080936884.png" alt=""></p><ol><li>设置默认代码格式化插件 搜索框搜索<code>editor.defaultFormatter</code>，将配置项选择为<code>Prettier</code></li></ol><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202312080937463.png" alt="image-20231208093731066"></p><ol><li>设置保存时候，自动格式化</li></ol><p>搜索框搜索<code>editor.formatOnSave</code>，勾选</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202312080937648.png" alt="image-20231208093756725"></p><p>可以结合<code>Eslint</code>使得代码更加规范，默认只提供代码风格检测功能，不能开启代码格式化功能</p><p><img src="https://nnaigos.oss-cn-hangzhou.aliyuncs.com/imgs/202312080938667.png" alt="image-20231208093816316"></p><div class="danger custom-block"><p class="custom-block-title">❌ 注意</p><p>此方法配置，是全局，会把其他覆盖掉(比如有go环境)</p></div>',14),i=[a];function n(d,l,r,p,g,m){return e(),s("div",null,i)}const u=o(t,[["render",n]]);export{h as __pageData,u as default};
